</code></pre> <pre><code>package main

import (
    "bytes"
    "encoding/json"
    "fmt"
    "io"
    "net/http"
    "time"
)

type PresentationRequest struct {
    Topic       string `json:"topic"`
    SlideCount  int    `json:"slideCount"`
    ExportType  string `json:"exportType"`
}

func main() {
    data := PresentationRequest{
        Topic:      "Your presentation topic",
        SlideCount: 10,
        ExportType: "ppt",
    }

    jsonData, err := json.Marshal(data)
    if err != nil {
        fmt.Printf("Error marshaling JSON: %v", err)
        return
    }

    client := &amp;http.Client{Timeout: 10 * time.Second}
    req, err := http.NewRequest("POST", 
        "https://developers.presentations.ai/api/v1/topic/document", 
        bytes.NewBuffer(jsonData))
    if err != nil {
        fmt.Printf("Error creating request: %v", err)
        return
    }

    req.Header.Set("Authorization", "Bearer YOUR_API_KEY")
    req.Header.Set("Content-Type", "application/json")

    resp, err := client.Do(req)
    if err != nil {
        fmt.Printf("Error making request: %v", err)
        return
    }
    defer resp.Body.Close()

    body, err := io.ReadAll(resp.Body)
    if err != nil {
        fmt.Printf("Error reading response: %v", err)
        return
    }

    fmt.Printf("Response: %s\n", body)
}
