</code></pre> <pre><code>import Foundation

struct PresentationRequest: Codable {
    let topic: String
    let slideCount: Int
    let exportType: String
}

func createPresentation() async throws {
    let url = URL(string: "https://developers.presentations.ai/api/v1/topic/document")!

    let data = PresentationRequest(
        topic: "Your presentation topic",
        slideCount: 10,
        exportType: "ppt"
    )

    var request = URLRequest(url: url)
    request.httpMethod = "POST"
    request.setValue("Bearer YOUR_API_KEY", forHTTPHeaderField: "Authorization")
    request.setValue("application/json", forHTTPHeaderField: "Content-Type")

    let encoder = JSONEncoder()
    request.httpBody = try encoder.encode(data)

    let (responseData, response) = try await URLSession.shared.data(for: request)

    if let httpResponse = response as? HTTPURLResponse {
        print("Status code: \(httpResponse.statusCode)")
    }
}
